    if (!rst_n) begin
        fft_state           <= IDLE;
        sched.stage         <= 1;
        sched.k             <= 0;
        sched.j             <= 0;
        sched.m             <= 2;
        sched.half_m        <= 1;
        sched.twiddle_index <= 0;
        sched.twiddle_step  <= NFFT >> 1;
        fft_done_o          <= 0;

        power_ptr           <= 0;
        power_ptr_stage1    <= 0;
        power_ptr_stage2    <= 0;
        power_ptr_stage3    <= 0;
        power_ptr_stage4    <= 0;
        power_valid_stage1  <= 0;
        power_valid_stage2  <= 0;
        power_valid_stage3  <= 0;
        power_valid_stage4  <= 0;
        power_stage3        <= 0;
    end else begin
        fft_done_o <= 0;

        case (fft_state)
            IDLE: begin
                if (start_i) begin
                    fft_state           <= PROCESSING;
                    sched.stage         <= 1;
                    sched.k             <= 0;
                    sched.j             <= 0;
                    sched.m             <= 2;
                    sched.half_m        <= 1;
                    sched.twiddle_index <= 0;
                    sched.twiddle_step  <= NFFT >> 1;
                    power_ptr           <= 0;
                end
            end

            PROCESSING: begin
                // Pipeline Stage 1: Read and schedule
                stage1.even      <= x[even_ptr_sum[NFFT_LOG2 - 1:0]];
                stage1.odd       <= x[odd_ptr_sum[NFFT_LOG2 - 1:0]];
                stage1.twiddle   <= twiddles[sched.twiddle_index[NFFT_LOG2 - 1:0]];
                stage1.meta      <= sched;

