            DONE: begin
                fft_done_o         <= 1;
                power_ptr          <= 0;
                power_valid_stage1 <= 0;
                power_valid_stage2 <= 0;
                power_valid_stage3 <= 0;
                power_valid_stage4 <= 0;
                fft_state          <= IDLE;
            end

            default: fft_state <= IDLE;
        endcase
