genvar k;
generate
    for (k = 0; k < NFFT_LOG2; k = k + 1) begin : bit_reverse
        assign frame_ptr_reversal[k] = frame_ptr_i[NFFT_LOG2 - 1 - k];
    end
endgenerate

endmodule

